const trig = $("TelegramTrigger").item.json;
const msg  = trig.message || {};
const telegramText = msg.text || msg.caption || "";
let whisperText = "";
try { whisperText = ($json && $json.text) || ""; } catch (e) {}
const inputText = (whisperText && whisperText.trim()) ? whisperText : telegramText;
return [{ json: { input_text: inputText, chat_id: msg.chat && msg.chat.id, is_voice: !!msg.voice } }];

