// Берём ответ Polza/OpenAI-compatible если есть, иначе fallback
const chatId = $("Normalize Input").item.json.chat_id;
let text = "";
try {
  const j = $json;
  // OpenAI-compatible shape
  const c1 = j && j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content;
  if (typeof c1 === 'string' && c1.trim()) text = c1.trim();
  // Legacy Ollama shape (на случай если кто-то вернёт старый формат)
  if (!text) {
    const c2 = j && j.message && j.message.content;
    if (typeof c2 === 'string' && c2.trim()) text = c2.trim();
  }
} catch (e) {}
if (!text) {
  text = 'Бот получил сообщение, но AI-модуль временно не подключен.';
}
return [{ json: { chat_id: chatId, text } }];

// ── Inputs ────────────────────────────────────────────────────────────────
const apts = $('Load Apartments').all().map(i => i.json);
const bks  = $('Load Bookings Window').all().map(i => i.json);
const gaps = $('Load Gap Windows').all().map(i => i.json);
const recs = $('Load Pricing Recs').all().map(i => i.json);
const competitorRows = $('Load Competitor Sources').all().map(i => i.json);
const msg  = $('Normalize Input').first().json.text || '';

// ── Bookings ────────────────────────────────────────────────────────────────
let booksText = 'БРОНИРОВАНИЯ (ближайшие 60 дней):\n';
if (bks.length === 0) {
  booksText += '  Нет броней в ближайшие 60 дней.\n';
} else {
  for (const b of bks) {
    booksText += `  • Апарт ${b.apartment_id}: ${b.checkin_at?.slice(0,10)} → ${b.checkout_at?.slice(0,10)} (${b.guests_name || 'гость'}, ${b.status})\n`;
  }
}

// ── Apartments ──────────────────────────────────────────────────────────────
let aptsText = 'АПАРТАМЕНТЫ:\n';
for (const a of apts) {
  aptsText += `  • ID ${a.id}: ${a.name || 'Апарт '+a.id}, базовая цена=${a.base_price || '?'} ₽/сут\n`;
}

// ── Gap Windows ──────────────────────────────────────────────────────────────
let gapsText = 'МАЛЕНЬКИЕ ОКНА / GAP WINDOWS (1–3 ночи между бронями):\n';
const openGaps = gaps.filter(g => g.status === 'open');
if (openGaps.length === 0) {
  gapsText += '  Маленьких окон сейчас не найдено.\n';
} else {
  for (const g of openGaps) {
    gapsText += `  • Апарт ${g.apartment_id}: ${g.gap_start} → ${g.gap_end} (${g.nights}н) — ${g.recommendation || ''}`;
    if (g.estimated_loss) gapsText += `, потеря ~${Math.round(g.estimated_loss)} ₽`;
    gapsText += '\n';
  }
}

// ── Pricing Recommendations (C3.8 net/gross/direct) ─────────────────────────
let recsText = 'ЦЕНОВЫЕ РЕКОМЕНДАЦИИ (рынок = цена для гостя; RC net = ставка под агрегатор):\n';
const draftRecs = recs.filter(r => r.status === 'draft' || r.status === 'approved');
if (draftRecs.length === 0) {
  recsText += '  Рекомендаций пока нет.\n';
} else {
  for (const r of draftRecs) {
    const g = Math.round(Number(r.recommended_guest_price ?? r.recommended_price));
    const rc = r.rc_net_price != null ? Math.round(Number(r.rc_net_price)) : null;
    const dp = r.direct_price != null ? Math.round(Number(r.direct_price)) : null;
    const dg = r.direct_owner_gain != null ? Math.round(Number(r.direct_owner_gain)) : null;
    const sg = r.direct_savings_for_guest != null ? Math.round(Number(r.direct_savings_for_guest)) : null;
    recsText += `  • Апарт ${r.apartment_id} (${r.date_from}→${r.date_to}): ${r.recommendation_type} — цель для гостя ~${g} ₽ (как прежний recommended)\n`;
    if (rc != null) recsText += `    RealtyCalendar net (примерно): ~${rc} ₽ на ночь — чтобы после наценки агрегатора попасть в цель для гостя.\n`;
    if (dp != null && dg != null && sg != null) {
      recsText += `    Прямая продажа: ~${dp} ₽ для гостя; гость экономит ~${sg} ₽ VS агрегатор, вы больше на ~${dg} ₽ VS net RC.\n`;
    }
    recsText += `    Confidence: ${r.confidence?.toFixed ? r.confidence.toFixed(2) : r.confidence}\n`;
    recsText += `    Причина: ${r.reason}\n`;
  }
}
recsText += '  ОТВЕТЫ: «Почему RC ниже?» — ставим NET; агрегатор добавляет ~' + (
  draftRecs[0]?.aggregator_markup_percent != null
    ? draftRecs[0].aggregator_markup_percent
    : 18
) + '% для гостя. «Цена RC?» — rc_net_price. «Цена напрямую гостю?» — direct_price. «Что теряем на агрегаторе?» — сравни expected guest vs прямое по строке выше.\n';
recsText += '  ⚠️ Рекомендации носят advisory-характер. Цены не меняются автоматически.\n';

// ── Competitor Sources (C1.5) ─────────────────────────────────────────────────
let compText = 'ПРЯМЫЕ КОНКУРЕНТЫ / MARKET SOURCES (C1.5):\n';
const activeSources = competitorRows.filter(c => c.status === 'active');
const excludedSources = competitorRows.filter(c => c.status !== 'active');

if (activeSources.length === 0) {
  compText += '  Активных конкурентов не найдено.\n';
} else {
  compText += `  Активных конкурентов: ${activeSources.length}\n`;
  for (const c of activeSources) {
    const priceRange = c.price_low && c.price_high ? `${c.price_low}–${c.price_high} ₽/сут` : 'цена не указана';
    const latestPrice = c.latest_price ? `${Math.round(c.latest_price)} ₽/сут` : 'нет данных';
    const lastObserved = c.last_observed_at ? new Date(c.last_observed_at).toLocaleDateString('ru-RU') : 'никогда';
    const staleWarn = c.is_stale ? ' ⚠️ данные устарели' : '';
    compText += `  • ${c.name} (similarity ${c.similarity_score}%)\n`;
    compText += `    Платформа: ${c.source_platform}, район: ${c.district || '?'}\n`;
    compText += `    Цена сезона: ${priceRange}${staleWarn}\n`;
    compText += `    Последнее наблюдение: ${latestPrice} (${lastObserved})\n`;
  }
}

if (activeSources.length > 0) {
  const prices = activeSources.map(c => c.latest_price).filter(p => p);
  if (prices.length > 0) {
    const sorted = prices.map(p => parseFloat(p)).sort((a,b)=>a-b);
    const median = sorted[Math.floor(sorted.length/2)];
    compText += `  Рыночная медиана по конкурентам: ~${Math.round(median)} ₽/сут\n`;
  }
  const hasStale = activeSources.some(c => c.is_stale);
  if (hasStale) {
    compText += `  ⚠️ Часть данных конкурентов — seed/устаревшие. Рекомендуется ручная проверка.\n`;
  }
}

// ── Market Quality & Cohorts (C3.4) ─────────────────────────────────────────
let marketQualityText = 'КАЧЕСТВО РЫНОЧНЫХ ДАННЫХ (кластеры конкурентов C3.4):\n';

// Cohort info for №40/41/42 — standard_family_2room
const standardSources = activeSources.filter(c =>
  c.cohort_code === 'standard_family_2room' || !c.cohort_code
);
const standardPrices = standardSources
  .map(c => c.latest_price ? parseFloat(c.latest_price) : null)
  .filter(p => p);
const standardMedian = standardPrices.length > 0
  ? standardPrices.sort((a,b)=>a-b)[Math.floor(standardPrices.length/2)]
  : null;

marketQualityText += `  ОБЪЕКТЫ №40, 41, 42 — кластер: Семейные 2-комнатные 4–5 гостей\n`;
marketQualityText += `    Активных источников: ${standardSources.length}/3 (мин. рекомендуется 5–7)\n`;
if (standardMedian) {
  marketQualityText += `    Медиана по кластеру: ~${Math.round(standardMedian)} ₽/сут\n`;
}
const standardQuality = standardSources.length >= 5 ? 'хорошее' :
  standardSources.length >= 3 ? 'среднее' : 'низкое — нужно добавить конкурентов';
marketQualityText += `    Качество данных: ${standardQuality}\n`;
const hasStaleStandard = standardSources.some(c => c.is_stale);
if (hasStaleStandard) {
  marketQualityText += `    ⚠️ Данные seed/устаревшие. Живые цены не подтверждены.\n`;
}

// №50 — large_family_house_territory
const largeSources = activeSources.filter(c =>
  c.cohort_code === 'large_family_house_territory'
);
marketQualityText += `\n  ОБЪЕКТ №50 — кластер: Крупные объекты 6–8 гостей с территорией\n`;
if (largeSources.length === 0) {
  marketQualityText += `    ⚠️ ПРЯМЫХ КОНКУРЕНТОВ ДЛЯ №50 НЕТ (0 источников)\n`;
  marketQualityText += `    Рекомендации по №50 — ПРЕДВАРИТЕЛЬНЫЕ (confidence ≤ 0.45)\n`;
  marketQualityText += `    Требуется: найти 3–5 домов/коттеджей 6–8 гостей с двором в Геленджике\n`;
  marketQualityText += `    Платформы: gelendzhik.travel, travelandia.ru, sutochno.ru\n`;
} else {
  marketQualityText += `    Источников: ${largeSources.length}\n`;
  const largeQuality = largeSources.length >= 5 ? 'хорошее' :
    largeSources.length >= 3 ? 'достаточное' : 'недостаточное — рекомендации предварительные';
  marketQualityText += `    Качество: ${largeQuality}\n`;
}

// System note for the bot about №50 recommendations
marketQualityText += `\n  ВАЖНО ДЛЯ БОТА:\n`;
marketQualityText += `  • При вопросах о цене №50 — всегда упоминать, что данные предварительные.\n`;
marketQualityText += `  • №50 сравнивается с домами/этажами 6–8 гостей, а НЕ с квартирами 4–5 гостей.\n`;
marketQualityText += `  • Confidence рекомендаций по №50 ≤ 0.45 до набора 3+ прямых конкурентов.\n`;
marketQualityText += `  • Для повышения точности нужно вручную добавить 3–5 конкурентов крупного формата.\n`;

// Prepared bot Q&A topics (context hints)
marketQualityText += `\n  ОТВЕТЫ НА ТИПИЧНЫЕ ВОПРОСЫ ВЛАДЕЛЬЦА:\n`;
marketQualityText += `  • "Почему №50 сравнивается отдельно?" — потому что это дом 6–8 гостей с территорией, а не квартира.\n`;
marketQualityText += `  • "Достаточно ли данных по рынку?" — для №40/41/42: ${standardQuality}. Для №50: ${largeSources.length === 0 ? 'нет данных, нужно добавить конкурентов' : 'есть ' + largeSources.length + ' источников'}.\n`;
marketQualityText += `  • "Каких конкурентов нужно добавить?" — для №50: дома/коттеджи/этажи 6–8 гостей с двором, цена 7000–10000 ₽.\n`;
marketQualityText += `  • "Почему рекомендация по №50 менее уверенная?" — потому что нет прямых аналогов в базе. Нужно 3+ источника кластера.\n`;

// ── Final context ─────────────────────────────────────────────────────────────
const context_text = [
  '=== КОНТЕКСТ ДЛЯ ОТВЕТА ВЛАДЕЛЬЦУ ===',
  aptsText,
  booksText,
  gapsText,
  recsText,
  compText,
  marketQualityText,
  '=== КОНЕЦ КОНТЕКСТА ==='
].join('\n');

return [{ json: { context_text, user_message: msg } }];
